/* eslint-disable max-lines */
/**
 * wdpr-drawer - Unified drawer component
 * Desktop/Tablet: side panel (left/right) | Mobile: half-sheet with drag + snap
 * Features: VisualViewport anchoring, focus trap, backdrop/ESC close, velocity-aware drag
 */

import { Component, Prop, h, Element, Watch, Event, EventEmitter, Host, State } from '@stencil/core';
import { customTwMerge, twMerge, generateRandId } from '../../utils/utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';

export type DrawerPosition = 'left' | 'right';
@Component({
  tag: 'wdpr-drawer',
  styleUrl: 'wdpr-drawer.css',
  shadow: true,
})
export class WdprDrawer {
  // ────────────────────────── Public API ─────────────────────────

  @Element() el!: HTMLWdprDrawerElement;

  /** Which side the drawer slides from (desktop side-panel mode). */
  @Prop() position: DrawerPosition = 'right';

  /** Open state (reflects). In uncontrolled mode this is mutated internally. */
  @Prop({ mutable: true, reflect: true }) isOpen = false;

  /** Title/Subtitle for fallback header + a11y. */
  @Prop() titleText = 'Title';
  @Prop() subtitleText = 'Subtitle';

  /** Optional leading icon for fallback header. */
  @Prop() leadingIcon?: string;

  /** Primary action label for fallback footer. */
  @Prop() buttonText = 'Primary Action';

  /** Enable close affordances (X, ESC, backdrop). */
  @Prop({ mutable: true, reflect: true }) isCloseable = true;

  /** Show optional “Back” button in header. */
  @Prop({ mutable: true, reflect: true }) showBackButton = false;

  /** Disable closing with the Escape key. */
  @Prop({ mutable: true, reflect: true }) disableEscClose = false;

  /** Desktop side-panel width (e.g., "26rem"). */
  @Prop() width: string = '26rem';

  /** Visual theme surface. 'primary' or 'secondary' */
  @Prop({ reflect: true }) colorMode: 'primary' | 'secondary' = 'primary';

  /** Visual header color mode. 'primary' or 'secondary' */
  @Prop({ reflect: true }) headerColorMode: 'primary' | 'secondary' = 'primary';

  /** Divider between header and content. */
  @Prop({ mutable: true, reflect: true }) showDivider = true;

  /** Show elevation shadow. */
  @Prop({ mutable: true, reflect: true }) showElevation = true;

  /** Enable drag on the half-sheet (mobile). */
  @Prop() isDraggable = true;

  /** Animation duration (ms). */
  @Prop() animationMs = 240;

  /** Close when tapping the backdrop. */
  @Prop() closeOnBackdrop = true;

  /** Controlled mode: do not mutate `isOpen` internally. */
  @Prop({ reflect: true }) controlled = false;

  /** Half-sheet max width (px). Keeps the sheet centered with margins on large phones/tablets. */
  @Prop() halfStackMaxWidth = 640;

  /** Avatar image source for mobile half-stack drawer */
  @Prop() avatarImageSrc?: string;

  /** Shows the footer section. by default is true */
  @Prop() showFooter = true;

  /** Optional initial open height for mobile half-sheet (percent of viewport). If omitted, uses auto content height. */
  @Prop() initialOpenPercent?: number;

  // ─────────────────────────── Events ───────────────────────────

  @Event({ eventName: 'drawerOpened' }) drawerOpened!: EventEmitter<void>;
  @Event({ eventName: 'drawerClosed' }) drawerClosed!: EventEmitter<void>;
  @Event({ eventName: 'drawerCloseRequested' }) drawerCloseRequested!: EventEmitter<void>;
  @Event({ eventName: 'back' }) back!: EventEmitter<void>;
  @Event({ eventName: 'primaryAction' }) primaryAction!: EventEmitter<void>;

  // ───────────────────── Internal state/refs ────────────────────

  private _panelRef!: HTMLDivElement;
  private _bodyRef!: HTMLElement;
  private _footerRef!: HTMLElement;

  private _headingId = `wdpr-drawer-h-${generateRandId()}`;
  private _previouslyFocusedEl: Element | null = null;

  @State() isDragging = false;
  @State() visiblePx = 0;
  @State() startVisiblePx = 0;
  @State() layoutIsMobile = false;
  @State() isBodyScrolled = false;
  @State() isOnPanel = false;

  private _prevLayoutIsMobile: boolean | null = null;
  private _mq?: MediaQueryList;
  private _parentPanelEl: HTMLElement | null = null;

  // drag metrics
  private _startY = 0;
  private _footerHeight = 0;

  // focus trap
  private _focusableEls: HTMLElement[] = [];
  private _firstFocusableEl: HTMLElement | null = null;
  private _lastFocusableEl: HTMLElement | null = null;
  private _listenersAttached = false;
  private _isRefocusing = false;
  private _isSentinelHandoff = false;
  private _mo?: MutationObserver;

  private _resizeRaf?: number;

  private static FOCUSABLE_SELECTORS = [
    'a[href]',
    'area[href]',
    'button:not([disabled])',
    'input:not([disabled])',
    'select:not([disabled])',
    'textarea:not([disabled])',
    'iframe',
    '[tabindex]:not([tabindex="-1"])',
    '[contenteditable="true"]',
  ].join(',');

  // ────────────────────────── Layout mode ───────────────────────

  private _onMediaChange = (e: MediaQueryListEvent) => {
    this._prevLayoutIsMobile = this.layoutIsMobile;
    this.layoutIsMobile = e.matches;

    if (this._prevLayoutIsMobile === null || this._prevLayoutIsMobile === this.layoutIsMobile) return;
    if (!this._panelRef) return;

    if (this.layoutIsMobile) {
      if (this.isOpen) {
        const targetPx = this._resolveInitialMobileVisiblePx();
        this._applyVisible(targetPx, false);
      } else {
        this._applyVisible(0, false);
      }
    } else {
      // Switched → Desktop side-panel
      if (this.isOpen) {
        this._panelRef.style.transform = 'translateX(0)';
        this._setProgress(this._getViewportHeight());
      } else {
        this._panelRef.style.transform = '';
        this._setProgress(0);
      }
    }
  };

  componentWillLoad() {
    this._detectParentPanel();
    if (typeof window !== 'undefined' && 'matchMedia' in window) {
      this._mq = window.matchMedia('(max-width: 767px)');
      this.layoutIsMobile = this._mq.matches;
      this._syncViewportCSSVars();
      this._mq.addEventListener('change', this._onMediaChange);
      window.addEventListener('orientationchange', this._onViewportResize);
      window.visualViewport?.addEventListener('scroll', this._onViewportResize, { passive: true });
    }
  }

  /** Check if a panel element is open (handles both attribute and property). */
  private _isPanelOpen(panelEl: HTMLElement): boolean {
    if ('isOpen' in panelEl && (panelEl as unknown as { isOpen: boolean }).isOpen === true) return true;
    const isOpenAttr = panelEl.getAttribute('is-open');

    return isOpenAttr !== null && isOpenAttr !== 'false';
  }

  /** Detect if this drawer is inside an open panel and cache reference. */
  private _detectParentPanel(): void {
    let parent = this.el.parentElement;
    while (parent) {
      if (parent.tagName?.toLowerCase() === 'wdpr-panel' && this._isPanelOpen(parent)) {
        this._parentPanelEl = (parent.shadowRoot?.querySelector('[part="panel"]') as HTMLElement) || parent;
        this.isOnPanel = true;

        return;
      }
      parent = parent.parentElement;
    }
    const panels = document.querySelectorAll('wdpr-panel');
    for (const panel of Array.from(panels)) {
      if (this._isPanelOpen(panel as HTMLElement)) {
        this._parentPanelEl = ((panel as HTMLElement).shadowRoot?.querySelector('[part="panel"]') as HTMLElement) || (panel as HTMLElement);
        this.isOnPanel = true;

        return;
      }
    }

    this._parentPanelEl = null;
    this.isOnPanel = false;
  }

  componentDidLoad(): void {
    if (this.isOpen) this._onOpen(false);
    window.visualViewport?.addEventListener('resize', this._onViewportResize);
    window.addEventListener('resize', this._onViewportResize);
    this._syncViewportCSSVars();
  }

  disconnectedCallback(): void {
    this._detachGlobalListeners();
    document.body.classList.remove('overflow-hidden');
    this._mo?.disconnect();
    this._mo = undefined;
    window.visualViewport?.removeEventListener('resize', this._onViewportResize);
    window.removeEventListener('resize', this._onViewportResize);
    window.removeEventListener('orientationchange', this._onViewportResize);
    window.visualViewport?.removeEventListener('scroll', this._onViewportResize);
  }

  @Watch('isOpen')
  onOpenChanged(): void {
    if (this.isOpen) {
      this._onOpen(true);
    } else {
      this._onClose(true);
    }
  }

  // ───────────────────────── Viewport utils ─────────────────────

  private _getViewportHeight(): number {
    if (this.isOnPanel && this._parentPanelEl) return Math.round(this._parentPanelEl.getBoundingClientRect().height);
    const vv = window.visualViewport?.height;

    return Math.round(vv || document.documentElement?.clientHeight || window.innerHeight || 0);
  }

  /** Sync CSS variables for VisualViewport geometry and derived sheet width. */
  private _syncViewportCSSVars(): void {
    let vw: number;
    let vh: number;
    let top: number;
    let left: number;

    // When on a panel, use the panel's bounds instead of the window
    if (this.isOnPanel && this._parentPanelEl) {
      const rect = this._parentPanelEl.getBoundingClientRect();
      vw = Math.round(rect.width);
      vh = Math.round(rect.height);
      top = Math.round(rect.top);
      left = Math.round(rect.left);
    } else {
      const vv = window.visualViewport;
      vw = Math.round(vv?.width ?? document.documentElement.clientWidth ?? window.innerWidth ?? 0);
      vh = Math.round(vv?.height ?? document.documentElement.clientHeight ?? window.innerHeight ?? 0);
      top = Math.round(vv?.offsetTop ?? 0);
      left = Math.round(vv?.offsetLeft ?? 0);
    }

    this._footerHeight = this._footerRef && this.showFooter ? this._footerRef.clientHeight : 0;
    const sheetW = this.isOnPanel ? vw : Math.max(0, Math.min(vw, this.halfStackMaxWidth));
    const vvh = this._isMobileHalfStack ? vh * 0.9 : vh;
    this.el.style.setProperty('--vvh', `${vvh}px`);
    this.el.style.setProperty('--pbottom', `${this._footerHeight}px`);
    this.el.style.setProperty('--vvw', `${vw}px`);
    this.el.style.setProperty('--vvtop', `${top}px`);
    this.el.style.setProperty('--vvleft', `${left}px`);
    this.el.style.setProperty('--sheet-w', `${sheetW}px`);
  }

  // ─────────────────────── Open / Close flow ────────────────────

  private _onOpen(animate: boolean): void {
    this.drawerOpened.emit();
    this._rememberOpener();

    document.body.classList.add('overflow-hidden');

    this._detectParentPanel();

    if (this._panelRef) {
      this._panelRef.style.transition = 'none';
      if (this._isMobileHalfStack) {
        // Mobile: position below viewport
        this._panelRef.style.transform = 'translateY(100vh)';
      } else {
        // Desktop: position off-screen to the side
        const offScreen = this.position === 'right' ? 'translateX(100%)' : 'translateX(-100%)';
        this._panelRef.style.transform = offScreen;
      }
    }

    // Also hide footer immediately
    if (this._footerRef) {
      this._footerRef.style.transition = 'none';
      if (this._isMobileHalfStack) {
        this._footerRef.style.transform = 'translateY(100%)';
      } else {
        const offScreen = this.position === 'right' ? 'translateX(100%)' : 'translateX(-100%)';
        this._footerRef.style.transform = offScreen;
      }
    }

    if (typeof MutationObserver !== 'undefined') {
      this._mo?.disconnect();
      this._mo = new MutationObserver(() => this._prepareFocusTrap());
      this._mo.observe(this._panelRef, { subtree: true, childList: true });
    }

    this._prepareFocusTrap();
    this._attachGlobalListeners();

    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        if (!this.isOpen) return;

        this._syncViewportCSSVars();
        this._syncLayoutForCurrentMode(animate, true);
      });
    });

    setTimeout(() => (this._firstFocusableEl ?? this._panelRef).focus({ preventScroll: true }), 0);
  }

  private _onClose(animate: boolean): void {
    this.drawerClosed.emit();
    this._detachGlobalListeners();

    // Only remove overflow-hidden if there's no open panel behind this drawer
    if (!this.isOnPanel) {
      document.body.classList.remove('overflow-hidden');
    }

    this._mo?.disconnect();
    this._mo = undefined;

    if (this._isMobileHalfStack) this._applyVisible(0, animate);

    this._focusableEls = [];
    this._firstFocusableEl = null;
    this._lastFocusableEl = null;

    this._restoreFocus();
  }

  // ────────────────────────── Layout sync ───────────────────────

  /** Recompute transforms/targets for current mode. */
  private _syncLayoutForCurrentMode(animate: boolean, isInitialOpen = false): void {
    if (!this._panelRef) return;

    if (this._isMobileHalfStack) {
      const targetPx = this._resolveInitialMobileVisiblePx();
      this.visiblePx = targetPx;
      this._applyVisible(targetPx, animate, isInitialOpen);

      return;
    }

    // Desktop side-panel - clear mobile height style
    this._panelRef.style.height = '';

    if (this.isOpen) {
      if (animate && isInitialOpen) {
        // Set initial off-screen position without transition
        const offScreenTransform = this.position === 'right' ? 'translateX(100%)' : 'translateX(-100%)';
        this._panelRef.style.transition = 'none';
        this._panelRef.style.transform = offScreenTransform;

        if (this._footerRef) {
          this._footerRef.style.transition = 'none';
          this._footerRef.style.transform = offScreenTransform;
        }

        // Short delay to ensure initial state is painted, then enable transition and animate
        setTimeout(() => {
          this._panelRef.style.transition = '';
          this._panelRef.classList.add('animating');
          this._panelRef.style.transform = 'translateX(0)';

          if (this._footerRef) {
            this._footerRef.style.transition = `transform ${this.animationMs}ms cubic-bezier(.22, .61, .36, 1)`;
            this._footerRef.style.transform = 'translateX(0)';
          }

          this._setProgress(this._getViewportHeight());
          window.setTimeout(() => {
            this._panelRef.classList.remove('animating');
            if (this._footerRef) this._footerRef.style.transition = '';
          }, this.animationMs);
        }, 20);
      } else {
        this._panelRef.style.transform = 'translateX(0)';
        if (this._footerRef) this._footerRef.style.transform = 'translateX(0)';
        this._setProgress(this._getViewportHeight());
      }
    } else {
      this._panelRef.style.transform = '';
      if (this._footerRef) this._footerRef.style.transform = '';
      this._setProgress(0);
    }
  }

  private _clamp(n: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, n));
  }

  private _getAutoOpenVisiblePx(minPx: number, maxPx: number): number {
    this._syncViewportCSSVars();

    const headerEl = this._panelRef?.querySelector('header') as HTMLElement | null;
    const headerH = headerEl ? Math.round(headerEl.getBoundingClientRect().height) : 0;

    const footerH = this._footerRef && this.showFooter ? this._footerRef.clientHeight : 0;

    let bodyContentH = 0;

    const slotEl = this._bodyRef?.querySelector('slot[name="body"]') as HTMLSlotElement | null;
    const assigned = slotEl?.assignedElements({ flatten: true }) ?? [];

    if (assigned.length) {
      bodyContentH = assigned.reduce((sum, node) => {
        const el = node as HTMLElement;

        const h = Math.max(el.scrollHeight || 0, Math.round(el.getBoundingClientRect().height) || 0, el.offsetHeight || 0);

        return sum + h;
      }, 0);
    } else {
      // Fallback: if slot not ready yet
      bodyContentH = this._bodyRef ? Math.round((this._bodyRef as HTMLElement).scrollHeight) : 0;
    }

    // Avatar visually extends above header; cushion so it doesn't feel clipped.
    const avatarExtra = this._isMobileHalfStack && this.avatarImageSrc ? 30 : 0;

    const desired = headerH + bodyContentH + footerH + avatarExtra;

    return this._clamp(desired, minPx, maxPx);
  }

  private _resolveInitialMobileVisiblePx(): number {
    const vh = this._getViewportHeight();
    const minPx = Math.round(vh * 0.25);
    const maxPx = Math.round(vh * 0.9);

    // Percent override wins
    if (typeof this.initialOpenPercent === 'number' && Number.isFinite(this.initialOpenPercent)) {
      const pct = this._clamp(this.initialOpenPercent, 25, 90);
      const px = Math.round((pct / 100) * vh);

      return this._clamp(px, minPx, maxPx);
    }

    // Otherwise use auto-fit
    return this._getAutoOpenVisiblePx(minPx, maxPx);
  }

  /** Progress [0..1] exposed as a CSS var for effects. */
  private _setProgress(pxVisible: number): void {
    const p = Math.min(1, Math.max(0, pxVisible / this._getViewportHeight()));
    this.el.style.setProperty('--drawer-progress', String(p));
  }

  /** Throttled viewport listener. */
  private _onViewportResize = () => {
    if (!this.isOpen || this.isDragging) return;
    if (this._resizeRaf) cancelAnimationFrame(this._resizeRaf);
    this._resizeRaf = requestAnimationFrame(() => {
      this._syncViewportCSSVars();
      this._syncLayoutForCurrentMode(false);
    });
  };

  // ───────────────────── Drag / Snap mechanics ──────────────────

  private _applyVisible(pxVisible: number, animate: boolean, isInitialOpen = false): void {
    const vv = window.visualViewport;
    const H = this._getViewportHeight();
    const offsetTop = Math.round(vv?.offsetTop ?? 0);

    const clamped = Math.max(0, Math.min(pxVisible, H));
    this.visiblePx = clamped;

    const ty = H - clamped + offsetTop;

    if (animate && isInitialOpen) {
      // Initial open: set off-screen position, then animate to target
      const initialTy = H + offsetTop;
      this._panelRef.style.transition = 'none';
      this._panelRef.style.transform = `translateY(${initialTy}px)`;
      this._panelRef.style.height = `${clamped}px`;

      if (this._footerRef) {
        this._footerRef.style.transition = 'none';
        this._footerRef.style.transform = 'translateY(100%)';
      }

      // Short delay to ensure initial state is painted, then enable transition and animate
      setTimeout(() => {
        this._panelRef.style.transition = '';
        this._panelRef.classList.add('animating');
        this._panelRef.style.transform = `translateY(${ty}px)`;

        if (this._footerRef) {
          this._footerRef.style.transition = `transform ${this.animationMs}ms cubic-bezier(.22, .61, .36, 1)`;
          this._footerRef.style.transform = 'translateY(0)';
        }

        this._setProgress(clamped);
        window.setTimeout(() => {
          this._panelRef.classList.remove('animating');
          if (this._footerRef) this._footerRef.style.transition = '';
        }, this.animationMs);
      }, 20);
    } else if (animate) {
      this._panelRef.classList.add('animating');
      this._panelRef.style.height = `${clamped}px`;
      this._panelRef.style.transform = `translateY(${ty}px)`;
      this._setProgress(clamped);
      window.setTimeout(() => this._panelRef.classList.remove('animating'), this.animationMs);
    } else {
      this._panelRef.style.height = `${clamped}px`;
      this._panelRef.style.transform = `translateY(${ty}px)`;
      this._setProgress(clamped);
    }
  }

  private _onPointerDown = (e: PointerEvent) => {
    if (!this.isOpen || !this._isMobileHalfStack || !this.isDraggable) return;

    const header = this._panelRef.querySelector('header');
    header?.setPointerCapture?.(e.pointerId);
    this.isDragging = true;
    this._panelRef.classList.remove('animating');

    this._startY = e.clientY;

    this.startVisiblePx = this.visiblePx;

    this._panelRef.style.transition = 'none';
    this._panelRef.style.willChange = 'transform';
    e.preventDefault();

    window.addEventListener('pointermove', this._onPointerMove, { passive: false });
    window.addEventListener('pointerup', this._onPointerUp, { passive: false, once: true });
  };

  private _onPointerMove = (e: PointerEvent) => {
    if (!this.isDragging) {
      return;
    }

    const vv = window.visualViewport;
    const offsetTop = Math.round(vv?.offsetTop ?? 0);

    // Calculate delta from START position
    const dy = this._startY - e.clientY; // Positive = dragging up

    // Calculate new visible pixels based on start position + delta
    let nextVisible = this.startVisiblePx + dy;

    const H = this._getViewportHeight();
    const maxVis = Math.round(H * 0.9);
    const minVis = Math.round(H * 0.3);

    if (nextVisible < minVis) {
      nextVisible = minVis;
    } else if (nextVisible > maxVis) {
      nextVisible = maxVis;
    }

    // Clamp to hard limits
    nextVisible = Math.max(minVis * 0.8, Math.min(maxVis * 1.1, nextVisible));

    // Update the transform and height so content scrolls properly during drag
    this._panelRef.style.transform = `translateY(${H - nextVisible + offsetTop}px)`;
    this._panelRef.style.height = `${nextVisible}px`;

    // Update current visible pixels for next frame
    this.visiblePx = nextVisible;
    this._setProgress(nextVisible);
    e.preventDefault();
  };

  private _onPointerUp = () => {
    if (!this.isDragging) return;

    this.isDragging = false;
    this._panelRef.style.willChange = '';

    // Re-enable transitions for settle animation
    this._panelRef.style.transition = 'transform 0.3s cubic-bezier(0.4, 0, 0.2, 1)';

    const H = this._getViewportHeight();
    const maxVis = Math.round(H * 0.9);
    const minVis = Math.round(H * 0.25); // keep consistent with _resolveInitialMobileVisiblePx

    // Just clamp and settle where user left it
    const clampedVisible = Math.max(minVis, Math.min(maxVis, this.visiblePx));
    this._applyVisible(clampedVisible, true);

    setTimeout(() => this._recheckScrollState(), this.animationMs + 50);
  };

  // ────────────────────────── A11y / Focus ──────────────────────

  private _getLocalActiveElement(): Element | null {
    // Get the deeply active element, traversing through shadow roots
    let active: Element | null = document.activeElement;
    while (active?.shadowRoot?.activeElement) {
      active = active.shadowRoot.activeElement;
    }

    return active;
  }

  private _rememberOpener(): void {
    this._previouslyFocusedEl = this._getLocalActiveElement();
  }

  private _isFocusable(el: Element | null | undefined): el is HTMLElement {
    if (!(el instanceof HTMLElement) || !el.isConnected || ((el instanceof HTMLInputElement || el instanceof HTMLButtonElement) && el.disabled)) return false;

    return typeof el.focus === 'function';
  }

  private _focusDeep(el: HTMLElement | null | undefined): boolean {
    if (!el) return false;
    try {
      el.focus({ preventScroll: true });
    } catch {}
    if (this._getLocalActiveElement() === el) return true;
    const sr = el.shadowRoot;
    if (sr) {
      const inner = sr.querySelector<HTMLElement>('button,[href],input,select,textarea,[tabindex]:not([tabindex="-1"])');
      if (inner) {
        try {
          inner.focus({ preventScroll: true });
        } catch {}
        const active = this._getLocalActiveElement();
        if (active === el || active === inner) return true;
      }
    }

    return false;
  }

  private _findFallbackFocus(): HTMLElement | null {
    const tagged = document.querySelector<HTMLElement>('[data-return-focus]');
    if (tagged && this._isFocusable(tagged)) return tagged;
    let cur: Element | null = this.el;
    while (cur) {
      if (this._isFocusable(cur)) return cur;
      cur = cur.parentElement;
    }
    const main = document.querySelector<HTMLElement>('main, [role="main"], [tabindex="0"]');

    return main && this._isFocusable(main) ? main : document.body;
  }

  private _restoreFocus(): void {
    const target = (this._previouslyFocusedEl as HTMLElement) ?? null;
    requestAnimationFrame(() => {
      if (!this._focusDeep(target)) this._focusDeep(this._findFallbackFocus());
    });
  }

  private _findFocusable(root: Element | ShadowRoot): HTMLElement[] {
    const els: HTMLElement[] = [];
    const crawl = (node: Element | ShadowRoot) => {
      const candidates = Array.from(node.querySelectorAll<HTMLElement>(WdprDrawer.FOCUSABLE_SELECTORS));
      for (const el of candidates) {
        if (el.hasAttribute('data-focus-sentinel') || el.closest('[data-focus-sentinel]')) continue;
        if (!el.hasAttribute('disabled') && el.tabIndex !== -1 && !els.includes(el)) els.push(el);
      }
      node.querySelectorAll('*').forEach(el => {
        const host = el as HTMLElement;
        if (host.shadowRoot) crawl(host.shadowRoot);
        if (el.tagName === 'SLOT') {
          const assigned = (el as HTMLSlotElement).assignedElements({ flatten: true });
          for (const a of assigned) {
            if ((a as HTMLElement).shadowRoot) crawl((a as HTMLElement).shadowRoot!);
            crawl(a);
          }
        }
      });
    };
    crawl(root);

    return els;
  }

  private _prepareFocusTrap(): void {
    const panelFocusable = this._findFocusable(this._panelRef);
    const footerFocusable = this._footerRef ? this._findFocusable(this._footerRef) : [];
    this._focusableEls = [...panelFocusable, ...footerFocusable];
    this._firstFocusableEl = this._focusableEls[0] ?? null;
    this._lastFocusableEl = this._focusableEls[this._focusableEls.length - 1] ?? null;
  }

  private _getCurrentFocusableFromEvent(e: KeyboardEvent): HTMLElement | null {
    const path = (e.composedPath?.() ?? []) as EventTarget[];
    const t0 = path[0];
    if (t0 instanceof HTMLElement && this._focusableEls.includes(t0)) return t0;
    const inPath = path.find(t => t instanceof HTMLElement && this._focusableEls.includes(t as HTMLElement)) as HTMLElement | undefined;
    if (inPath) return inPath;
    const active = (this.el.getRootNode() as Document | ShadowRoot).activeElement as HTMLElement | null;

    return active && this._focusableEls.includes(active) ? active : null;
  }

  private _attachGlobalListeners(): void {
    if (this._listenersAttached) return;
    document.addEventListener('keydown', this._onKeydown, true);
    document.addEventListener('focusin', this._onDocFocusIn, true);
    this._listenersAttached = true;
  }

  private _detachGlobalListeners(): void {
    if (!this._listenersAttached) return;
    document.removeEventListener('keydown', this._onKeydown, true);
    document.removeEventListener('focusin', this._onDocFocusIn, true);
    this._listenersAttached = false;
  }

  private _onDocFocusIn = (e: FocusEvent): void => {
    if (!this.isOpen || this._isRefocusing || this._isSentinelHandoff) return;
    const path = (e.composedPath?.() ?? []) as EventTarget[];
    const isInPanel = this._panelRef && path.includes(this._panelRef);
    const isInFooter = this._footerRef && path.includes(this._footerRef);
    if (!isInPanel && !isInFooter) {
      this._isRefocusing = true;
      try {
        this._prepareFocusTrap();
        (this._firstFocusableEl ?? this._panelRef).focus({ preventScroll: true });
        e.stopImmediatePropagation();
        e.preventDefault();
      } finally {
        this._isRefocusing = false;
      }
    }
  };

  private _onKeydown = (e: KeyboardEvent): void => {
    if (!this.isOpen || e.defaultPrevented) return;

    if (e.key === KEYBOARD_KEYS.ESCAPE && !this.disableEscClose) {
      e.stopPropagation();
      this._closeDrawer();

      return;
    }

    if (e.key !== KEYBOARD_KEYS.TAB) return;

    this._prepareFocusTrap();
    const count = this._focusableEls.length;

    if (count === 0) return;

    const first = this._firstFocusableEl;
    const last = this._lastFocusableEl;
    const current = this._getCurrentFocusableFromEvent(e);

    if (!first || !last) {
      e.preventDefault();
      this._panelRef.focus({ preventScroll: true });

      return;
    }

    if (!current) {
      e.preventDefault();
      first.focus({ preventScroll: true });

      return;
    }

    if (e.shiftKey && current === first) {
      e.preventDefault();
      last.focus({ preventScroll: true });

      return;
    }

    if (!e.shiftKey && current === last) {
      e.preventDefault();
      first.focus({ preventScroll: true });

      return;
    }
  };

  private _closeDrawer(): void {
    if (this.controlled) {
      this.drawerCloseRequested.emit();
    } else {
      this.isOpen = false;
    }
  }

  // ─────────────────────── Render helpers ───────────────────────

  private get _isMobileHalfStack(): boolean {
    return this.layoutIsMobile || this.isOnPanel;
  }

  private get _panelWidthClass(): string {
    return 'max-w-[100vw]';
  }

  private get _sideTransformClass(): string {
    return this.position === 'right' ? 'right-0 left-auto translate-x-full' : 'left-0 right-auto -translate-x-full';
  }

  private get _sideRadiusClass(): string {
    if (!this._isMobileHalfStack) {
      return this.position === 'right' ? 'rounded-tl-400 rounded-bl-400 rounded-tr-none rounded-br-none' : 'rounded-tr-400 rounded-br-400 rounded-tl-none rounded-bl-none';
    }

    return 'rounded-t-400';
  }

  private get _sideRadiusHeaderClass(): string {
    if (!this._isMobileHalfStack) {
      return this.position === 'right' ? 'rounded-tl-400 rounded-bl-none rounded-tr-none rounded-br-none' : 'rounded-tr-400 rounded-br-none rounded-tl-none rounded-bl-none';
    }

    return 'rounded-t-400';
  }

  private get _sideRadiusFooterClass(): string {
    // Desktop mode: clip the footer corner that matches the drawer's rounded edge
    if (!this._isMobileHalfStack) {
      return this.position === 'right' ? 'rounded-bl-400 rounded-tl-none rounded-tr-none rounded-br-none' : 'rounded-br-400 rounded-tr-none rounded-tl-none rounded-bl-none';
    }

    return '';
  }

  private get _panelBgClass(): string {
    return this.colorMode === 'secondary' ? 'bg-page-default-alt' : 'bg-surface-default';
  }

  /** Desktop width; mobile ignores and uses visual-viewport centering. */
  private get _panelStyle(): Record<string, string> {
    const w = this.width && this.width !== '' ? this.width : '26rem';

    return { width: w, maxWidth: '100vw' };
  }

  private get _panelLayoutClasses(): string {
    if (this._isMobileHalfStack) {
      const overflowClass = this.avatarImageSrc ? 'overflow-visible' : 'overflow-hidden';

      return customTwMerge(
        'fixed bottom-0',
        'translate-y-full', // JS sets precise transform
        'max-h-[var(--vvh)] pb-[env(safe-area-inset-bottom)]',
        this._sideRadiusClass,
        this._panelWidthClass,
        overflowClass,
        'flex flex-col',
        'will-change-transform',
        'transition-transform duration-300 ease-[cubic-bezier(.22,.61,.36,1)]',
        this._panelBgClass,
      );
    }

    return customTwMerge(
      'fixed top-0 bottom-0',
      this._sideTransformClass,
      this.isOpen ? 'translate-x-0' : '',
      'flex flex-col',
      'items-stretch content-stretch',
      this._panelBgClass,
      this._sideRadiusClass,
      this._panelWidthClass,
      'transition-transform duration-300 ease-[cubic-bezier(.22,.61,.36,1)]',
      'pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)]',
      'pointer-events-auto',
      'min-w-0 min-h-0 overflow-x-hidden overflow-y-auto',
    );
  }

  private get _drawerHeaderClasses(): string {
    const paddingTop = !this.isDraggable && (!this.avatarImageSrc || !this._isMobileHalfStack) ? 'pt-250' : '';
    const justifyContent = this.showBackButton && this.isCloseable ? 'justify-between' : 'justify-end';

    return twMerge('flex px-300 pb-200', paddingTop, justifyContent);
  }

  private get _headerClasses(): string {
    const headerColor = this.headerColorMode === 'secondary' ? 'bg-surface-default-alt' : 'bg-surface-default';
    // Use JS state for padding to stay in sync with layoutIsMobile
    const paddingTop = this._isMobileHalfStack ? '' : 'pt-400';
    // Allow overflow for avatar to extend above header
    const overflowClass = this._isMobileHalfStack && this.avatarImageSrc ? 'overflow-visible' : '';
    if (this.showDivider && this.isBodyScrolled) {
      const boxShadow = '[box-shadow:var(--theme-effect-000)_var(--theme-effect-025)_var(--theme-effect-100)_var(--theme-effect-000)_var(--color-plum-700-a16)]';

      return customTwMerge(
        'sticky top-0 border-stroke-neutral-light',
        this._sideRadiusHeaderClass,
        this.showElevation ? boxShadow : '',
        'flow-root',
        paddingTop,
        overflowClass,
        headerColor,
      );
    }

    return customTwMerge('sticky top-0 border-stroke-neutral-light flow-root', paddingTop, overflowClass, headerColor, this._sideRadiusHeaderClass);
  }

  private get _handleClasses(): string {
    const bgColor = this.headerColorMode === 'secondary' ? 'bg-surface-actionable-alt-focus' : 'bg-surface-neutral-light';

    return twMerge('rounded-pill w-500 h-050', bgColor);
  }

  private get _contentClasses(): string {
    const color = this.colorMode === 'secondary' ? 'bg-surface-default-alt' : 'bg-surface-default';

    return twMerge('min-w-0 min-h-0 flex flex-col flex-1 pt-300 overflow-hidden', color);
  }

  private _clickPrimary(): void {
    this.primaryAction.emit();
  }

  private _overlayClick(): void {
    if (this.closeOnBackdrop) this._closeDrawer();
  }

  // ────────────────────── Render-time handlers ──────────────────

  private _handleOverlayClick = (ev: CustomEvent<void>): void => {
    ev.stopPropagation();
    this._overlayClick();
  };

  private _handleBackClick = (ev: Event): void => {
    ev.stopPropagation();
    this.back.emit();
  };

  private _handleCloseClick = (ev: Event): void => {
    ev.stopPropagation();
    this._closeDrawer();
  };

  private _handlePrimaryClick = (ev: Event): void => {
    ev.stopPropagation();
    this._clickPrimary();
  };

  private _handleScrollChange = (ev: CustomEvent<{ position: number }>): void => {
    const position = ev.detail?.position ?? 0;
    this.isBodyScrolled = position > 0;
  };

  /** Recheck scroll state after resize - reset scrolled state, scrollbar will update on next scroll */
  private _recheckScrollState(): void {
    this.isBodyScrolled = false;
  }

  private _handleSentinelFocus(isStart: boolean): void {
    if (!this.isOpen) return;
    const target = isStart ? this._lastFocusableEl : this._firstFocusableEl;
    this._isSentinelHandoff = true;
    setTimeout(() => {
      (target ?? this._panelRef).focus();
      this._isSentinelHandoff = false;
    }, 0);
  }

  // ─────────────────────────── Rendering ────────────────────────

  render() {
    const labelledBy = this.titleText ? this._headingId : undefined;
    const ariaLabel = labelledBy ? undefined : this.titleText || 'Drawer';

    return (
      <Host style={{ '--anim-ms': `${this.animationMs}ms` }}>
        <wdpr-overlay cover open={this.isOpen} variant="scrim" role="presentation" a11y-label="Backdrop" onOverlayClick={this._handleOverlayClick} />

        {/* Panel */}
        <div
          style={{
            ...this._panelStyle, // desktop
            ...(this._isMobileHalfStack
              ? {
                  // Centered within the VisualViewport:
                  touchAction: 'pan-x',
                  width: 'var(--sheet-w)',
                  left: 'calc(var(--vvleft) + (var(--vvw) - var(--sheet-w)) / 2)',
                  top: 'var(--vvtop)',
                }
              : {}),
            paddingBottom: this.showFooter ? 'var(--pbottom)' : undefined,
          }}
          class={this._panelLayoutClasses}
          role="dialog"
          aria-modal="true"
          tabIndex={-1}
          aria-label={ariaLabel}
          aria-labelledby={labelledBy}
          ref={el => (this._panelRef = el as HTMLDivElement)}
        >
          {/* Focus sentinel (start) */}
          <div data-focus-sentinel="start" tabIndex={0} aria-hidden="true" class="sr-only" onFocus={() => this._handleSentinelFocus(true)} />

          {/* Header + drag handle */}
          <header class={this._headerClasses} part="header">
            {this.isDraggable && this._isMobileHalfStack && !this.avatarImageSrc && (
              <div class="mx-auto pt-100 pb-250 h-400 w-500" data-drag-handle onPointerDown={this._onPointerDown}>
                <div class={this._handleClasses} />
              </div>
            )}

            {/* Mobile half-stack avatar */}
            {this._isMobileHalfStack && this.avatarImageSrc && (
              <div class="flex h-400 pt-[34px] flex-col items-center self-stretch" data-drag-handle onPointerDown={this._onPointerDown}>
                <div class="absolute top-[-34px] mx-auto">
                  <wdpr-avatar isInteractive={false} showBorder imageSrc={this.avatarImageSrc} size="large" />
                </div>
              </div>
            )}

            <slot name="drawer-header">
              <div class={this._drawerHeaderClasses}>
                {this.showBackButton && <wdpr-icon-button iconName="back-thick" a11yLabel="Back" size="medium" variant="primary" onClick={this._handleBackClick} />}
                {this.isCloseable && <wdpr-icon-button iconName="close-reversed" a11yLabel="Close" size="medium" variant="primary" onClick={this._handleCloseClick} />}
              </div>
            </slot>

            <div class="flex flex-col">
              <slot name="header">
                <wdpr-text-header size="large" id={this._headingId} class="px-300" headerLabel={this.titleText} subtextLabel={this.subtitleText}>
                  {this.leadingIcon && <wdpr-icon-library size="medium" icon={this.leadingIcon} slot="leading-icon" decorative />}
                </wdpr-text-header>
              </slot>
              <slot name="header-content" />
              {this.showDivider && <div class="mt-200">{this.isBodyScrolled && <wdpr-divider orientation="horizontal" />}</div>}
            </div>
          </header>

          {/* Content */}
          <section class={this._contentClasses} part="content" ref={el => (this._bodyRef = el as HTMLElement)}>
            <wdpr-scrollbar orientation="vertical" size="medium" initialPosition={0} class="flex-1 min-h-0" tabIndex={-1} onScrollChange={this._handleScrollChange}>
              <slot name="body" />
            </wdpr-scrollbar>
          </section>
        </div>

        {/* Footer - outside panel to avoid transform interference */}
        {this.showFooter && (
          <footer
            ref={el => (this._footerRef = el as HTMLElement)}
            part="footer"
            class={customTwMerge('fixed bottom-0 z-[100000] overflow-hidden', this._sideRadiusFooterClass)}
            style={{
              ...(this._isMobileHalfStack
                ? {
                    width: 'var(--sheet-w)',
                    left: 'calc(var(--vvleft) + (var(--vvw) - var(--sheet-w)) / 2)',
                  }
                : {
                    width: this.width || '26rem',
                    maxWidth: '100vw',
                    ...(this.position === 'right' ? { right: '0' } : { left: '0' }),
                  }),
            }}
          >
            <slot name="footer">
              <wdpr-button-dock>
                <wdpr-button-bar slot="button-bar" layout="stacked">
                  <wdpr-button display="block" slot="primary-button" variant="primary" size="large" onClick={this._handlePrimaryClick}>
                    {this.buttonText}
                  </wdpr-button>
                </wdpr-button-bar>
              </wdpr-button-dock>
            </slot>
          </footer>
        )}

        {/* Focus sentinel (end) - after footer so footer is in tab order */}
        <div data-focus-sentinel="end" tabIndex={0} aria-hidden="true" class="sr-only" onFocus={() => this._handleSentinelFocus(false)} />
      </Host>
    );
  }
}
